import axios from 'axios';

// –î–Μ―è ―Ä–Α–Ζ―Ä–Α–±–Ψ―²–Κ–Η
// const API_BASE = 'http://localhost:8080/area-app/api';

// –î–Μ―è production (–Ψ―²–Ϋ–Ψ―¹–Η―²–Β–Μ―¨–Ϋ―΄–Ι –Ω―É―²―¨)
const API_BASE = '/area-app/api';

const api = axios.create({
  baseURL: process.env.NODE_ENV === 'development'
    ? 'http://localhost:8080/area-app/api'
    : '/area-app/api',
  headers: {
    'Content-Type': 'application/json'
  }
});

api.interceptors.request.use(config => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers.Authorization = token;
  }
  return config;
});

export const authAPI = {
  login: async (username, password) => {
    try {
      const response = await api.post('/login', { username, password });
      if (response.data.token) {
        localStorage.setItem('token', response.data.token);
        localStorage.setItem('username', username);
        return { success: true, data: response.data };
      }
    } catch (error) {
      return {
        success: false,
        message: error.response?.data?.error || '–û―à–Η–±–Κ–Α –Α–≤―²–Ψ―Ä–Η–Ζ–Α―Ü–Η–Η'
      };
    }
  },

  logout: async () => {
    const token = localStorage.getItem('token');
    if (token) {
      try {
        await api.post('/logout', {}, {
          headers: { Authorization: token }
        });
      } catch (error) {
        console.log('Logout completed (ignoring errors)');
      }
    }
    localStorage.removeItem('token');
    localStorage.removeItem('username');
  }
};  // βÜê –£–û–Δ –û–ù–ê! –ü–†–û–ü–Θ–©–ï–ù–ê –½–ê–ö–†–Ϊ–£–ê–°–©–ê–· –Γ–ö–û–ë–ö–ê –‰ –Δ–û–ß–ö–ê –Γ –½–ê–ü–·–Δ–û–ô!

export const pointAPI = {
  checkPoint: async (x, y, r) => {
    try {
      const body = { x, y, r };
      const response = await api.post('/check', body);
      return { success: true, data: response.data };
    } catch (error) {
      return {
        success: false,
        message: error.response?.data?.error || '–û―à–Η–±–Κ–Α –Ω―Ä–Ψ–≤–Β―Ä–Κ–Η ―²–Ψ―΅–Κ–Η'
      };
    }
  },

  getResults: async () => {
    try {
      const response = await api.get('/results');
      return { success: true, data: response.data };
    } catch (error) {
      return {
        success: false,
        message: error.response?.data?.error || '–û―à–Η–±–Κ–Α –Ζ–Α–≥―Ä―É–Ζ–Κ–Η ―Ä–Β–Ζ―É–Μ―¨―²–Α―²–Ψ–≤'
      };
    }
  },

  clearResults: async () => {
    try {
      await api.delete('/results');
      return { success: true };
    } catch (error) {
      return {
        success: false,
        message: error.response?.data?.error || '–û―à–Η–±–Κ–Α –Ψ―΅–Η―¹―²–Κ–Η'
      };
    }
  }
};

export const checkAuth = async () => {
  const token = localStorage.getItem('token');
  if (!token) return false;

  // –ü―Ä–Ψ―¹―²–Α―è –Ω―Ä–Ψ–≤–Β―Ä–Κ–Α - –Β―¹―²―¨ ―²–Ψ–Κ–Β–Ϋ –≤ localStorage
  // –ë–Ψ–Μ–Β–Β –Ϋ–Α–¥–Β–Ε–Ϋ–Ψ –Φ–Ψ–Ε–Ϋ–Ψ –Ω―Ä–Ψ–≤–Β―Ä–Η―²―¨ ―΅–Β―Ä–Β–Ζ /auth-check –Β―¹–Μ–Η –¥–Ψ–±–Α–≤–Η―²–Β ―²–Α–Κ–Ψ–Ι ―ç–Ϋ–¥–Ω–Ψ–Η–Ϋ―²
  return true;
};

export default api;
